    /// <summary>
    /// Wire-nav step of the two-pass populate pattern. Invoked exactly
    /// once by <c>GeoDataInitializer</c> after every catalog's first-pass
    /// static ctor has run. Populates each language's
    /// <c>SpokenInCountries</c> + <c>SpokenInCountryIso31661Alpha2Codes</c>
    /// (where the country's PrimaryLanguage matches) and
    /// <c>Locales</c> + <c>LocaleIetfBcp47Tags</c> (where the locale's
    /// Language matches) via the friend-assembly <c>internal set</c>
    /// accessors.
    /// </summary>
    internal static void WireNav()
    {
        var countriesByLanguage = new Dictionary<LanguageCode, List<Country>>();
        foreach (var country in CountryLookup.All)
        {
            if (country.PrimaryLanguage is null)
                continue;

            var code = country.PrimaryLanguage.Iso6391Code;
            if (!countriesByLanguage.TryGetValue(code, out var list))
            {
                list = new List<Country>();
                countriesByLanguage[code] = list;
            }

            list.Add(country);
        }

        var localesByLanguage = new Dictionary<LanguageCode, List<Locale>>();
        foreach (var locale in LocaleLookup.All)
        {
            if (locale.Language is null)
                continue;

            var code = locale.Language.Iso6391Code;
            if (!localesByLanguage.TryGetValue(code, out var list))
            {
                list = new List<Locale>();
                localesByLanguage[code] = list;
            }

            list.Add(locale);
        }

        foreach (var language in All)
        {
            if (countriesByLanguage.TryGetValue(language.Iso6391Code, out var countries))
            {
                language.SpokenInCountries = countries.ToArray();

                var countryCodeSet = new HashSet<CountryCode>();
                foreach (var c in countries)
                    countryCodeSet.Add(c.Iso31661Alpha2Code);

                language.SpokenInCountryIso31661Alpha2Codes = countryCodeSet.ToFrozenSet();
            }

            if (localesByLanguage.TryGetValue(language.Iso6391Code, out var locales))
            {
                language.Locales = locales.ToArray();

                var localeCodeSet = new HashSet<LocaleCode>();
                foreach (var l in locales)
                    localeCodeSet.Add(l.IetfBcp47Tag);

                language.LocaleIetfBcp47Tags = localeCodeSet.ToFrozenSet();
            }
        }
    }
